use std::path::PathBuf;

// Re-export the helper function to sub-modules if needed.
pub use test_helpers::{print_cdu_summary_to_file, hex_encode, verify_causal_chain};

// A helper function to find the project root, used by all test modules.
pub fn find_workspace_root() -> PathBuf {
    let mut path = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    loop {
        if path.join("Cargo.toml").exists() && path.join("crates").exists() {
            return path;
        }
        path = match path.parent() {
            Some(parent) => parent.to_path_buf(),
            None => panic!("Could not find workspace root."),
        };
    }
}
